"use strict";
/* ---------- question pictures ---------- */
function pieSVG(parts, shaded) {
  const cx = 50, cy = 50, r = 44;
  let p = "";
  for (let i = 0; i < parts; i++) {
    const a0 = -Math.PI / 2 + i * 2 * Math.PI / parts, a1 = a0 + 2 * Math.PI / parts;
    const x0 = cx + r * Math.cos(a0), y0 = cy + r * Math.sin(a0);
    const x1 = cx + r * Math.cos(a1), y1 = cy + r * Math.sin(a1);
    p += '<path d="M' + cx + ' ' + cy + ' L' + x0.toFixed(1) + ' ' + y0.toFixed(1) +
         ' A' + r + ' ' + r + ' 0 0 1 ' + x1.toFixed(1) + ' ' + y1.toFixed(1) + ' Z" fill="' +
         (i < shaded ? "#e8638c" : "#fff") + '" stroke="#5a4a2f" stroke-width="2.5" stroke-linejoin="round"/>';
  }
  return '<svg viewBox="-2 -2 104 104" style="height:96px">' + p + '</svg>';
}
function berryC(cx, cy) {
  return '<circle cx="' + cx + '" cy="' + cy + '" r="7" fill="#c9415a" stroke="#8f2c40" stroke-width="1.5"/>';
}
function berriesSVG(n) {
  let c = "";
  for (let i = 0; i < n; i++) c += berryC(10 + (i % 10) * 17, 10 + Math.floor(i / 10) * 18);
  const rows = Math.ceil(n / 10);
  const w = 10 + Math.min(n, 10) * 17, h = 2 + rows * 18;
  return '<svg viewBox="0 0 ' + w + ' ' + h + '" style="height:' + (rows * 30) + 'px">' + c + '</svg>';
}
function flowerG(cx, cy) {
  let p = "";
  for (let i = 0; i < 5; i++) {
    const a = -Math.PI / 2 + i * 2 * Math.PI / 5;
    p += '<circle cx="' + (cx + 6.5 * Math.cos(a)).toFixed(1) + '" cy="' + (cy + 6.5 * Math.sin(a)).toFixed(1) + '" r="4.5" fill="#e6a4b8"/>';
  }
  return p + '<circle cx="' + cx + '" cy="' + cy + '" r="4" fill="#e8c84f"/>';
}
function shareSVG(a, n) {
  if (a > 20) return "";
  // sharing as it's done in class: the berries are dealt out under the flowers,
  // one equal group each — the child counts one flower's share to find the answer
  const q = a / n;
  const cols = q > 5 ? 2 : 1, rowsPer = Math.ceil(q / cols);
  const gw = Math.max(26, cols * 17 + 10), gap = 9;
  let c = "";
  for (let i = 0; i < n; i++) {
    const gx = 6 + i * (gw + gap), cx = gx + gw / 2;
    c += flowerG(cx, 13);
    // a soft "plate" around each share, like the sharing circles on a worksheet
    const pw = cols * 17 + 10, ph = rowsPer * 18 + 8;
    c += '<rect x="' + (cx - pw / 2) + '" y="28" width="' + pw + '" height="' + ph +
         '" rx="9" fill="none" stroke="#d8cdb4" stroke-width="1.5" stroke-dasharray="4 3"/>';
    for (let j = 0; j < q; j++) {
      const bx = cx - (cols * 17) / 2 + 8.5 + (j % cols) * 17;
      const by = 41 + Math.floor(j / cols) * 18;
      c += berryC(bx, by);
    }
  }
  const w = 12 + n * gw + (n - 1) * gap, h = 36 + rowsPer * 18 + 8;
  return '<svg viewBox="0 0 ' + w + ' ' + h + '" style="height:' + Math.min(104, h * 1.5) + 'px">' + c + '</svg>';
}

// counters in pairs — the classroom model for odd & even: everything pairs up,
// or one golden counter is left without a partner
function pairsSVG(n) {
  let s = "";
  for (let i = 0; i < n; i++) {
    const col = Math.floor(i / 2), row = i % 2, lone = i === n - 1 && n % 2 === 1;
    s += '<circle cx="' + (12 + col * 22) + '" cy="' + (12 + row * 22) + '" r="8.5" fill="' +
         (lone ? "#e8b73a" : "#6fa8dc") + '" stroke="' + (lone ? "#a8842a" : "#41719c") + '" stroke-width="1.5"/>';
  }
  const w = 24 + (Math.ceil(n / 2) - 1) * 22;
  return '<svg viewBox="0 0 ' + w + ' 46" style="height:74px">' + s + '</svg>';
}
// 2-D shapes, drawn flat and friendly like a classroom shape poster
const SHAPES = [
  { id: "circle", name: "circle", sides: 0, corners: 0, lvl: 0, f: "#e6a4b8", s: "#b8718a" },
  { id: "triangle", name: "triangle", sides: 3, corners: 3, lvl: 0, f: "#9ec7e8", s: "#41719c" },
  { id: "square", name: "square", sides: 4, corners: 4, lvl: 0, f: "#a8d8a0", s: "#5a8f52" },
  { id: "rectangle", name: "rectangle", sides: 4, corners: 4, lvl: 0, f: "#e8c84f", s: "#b89a2a" },
  { id: "pentagon", name: "pentagon", sides: 5, corners: 5, lvl: 1, f: "#c4a8e0", s: "#8a6ab0" },
  { id: "hexagon", name: "hexagon", sides: 6, corners: 6, lvl: 1, f: "#e0945a", s: "#a86a38" },
  { id: "octagon", name: "octagon", sides: 8, corners: 8, lvl: 2, f: "#d9534f", s: "#9e3a36" }
];
function shapePic(id) {
  const sh = SHAPES.find(x => x.id === id);
  let body;
  if (id === "circle") body = '<circle r="28"';
  else if (id === "square") body = '<rect x="-25" y="-25" width="50" height="50"';
  else if (id === "rectangle") body = '<rect x="-33" y="-21" width="66" height="42"';
  else {
    const pts = [];
    for (let k = 0; k < sh.sides; k++) {
      const a = -Math.PI / 2 + k * 2 * Math.PI / sh.sides;
      pts.push((30 * Math.cos(a)).toFixed(1) + "," + (30 * Math.sin(a)).toFixed(1));
    }
    body = '<polygon points="' + pts.join(" ") + '"';
  }
  return '<svg viewBox="-40 -38 80 76" style="height:88px">' + body +
         ' fill="' + sh.f + '" stroke="' + sh.s + '" stroke-width="3" stroke-linejoin="round"/></svg>';
}

function appleG(cx, cy, fill, stroke) {
  return '<circle cx="' + cx + '" cy="' + cy + '" r="7.5" fill="' + fill + '" stroke="' + stroke + '" stroke-width="1.5"/>' +
         '<path d="M' + cx + " " + (cy - 7) + " Q " + (cx + 1) + " " + (cy - 11) + " " + (cx + 4) + " " + (cy - 12) +
         '" stroke="#6b8f3c" stroke-width="2" fill="none" stroke-linecap="round"/>';
}
function addPicSVG(a, b) {
  const cols = n => Math.min(n, 5), rows = n => Math.ceil(n / 5);
  let s = "";
  for (let i = 0; i < a; i++) s += appleG(13 + (i % 5) * 19, 18 + Math.floor(i / 5) * 21, "#d9534f", "#9e3a36");
  const xb = 13 + cols(a) * 19 + 10;
  const h = 8 + Math.max(rows(a), rows(b)) * 21;
  s += '<text x="' + (xb - 12) + '" y="' + (h / 2 + 7) + '" font-size="18" font-weight="700" fill="#5a4a2f">+</text>';
  for (let i = 0; i < b; i++) s += appleG(xb + 10 + (i % 5) * 19, 18 + Math.floor(i / 5) * 21, "#8db84e", "#5f8a33");
  const w = xb + 12 + cols(b) * 19;
  return '<svg viewBox="0 0 ' + w + " " + h + '" style="height:' + Math.min(88, h * 1.8) + 'px">' + s + '</svg>';
}
function biscuitG(cx, cy, eaten) {
  let s = '<g' + (eaten ? ' opacity="0.32"' : "") + '><circle cx="' + cx + '" cy="' + cy + '" r="8" fill="#d8a35a" stroke="#a8763c" stroke-width="1.5"/>' +
    '<circle cx="' + (cx - 3) + '" cy="' + (cy - 2) + '" r="1.6" fill="#6b4226"/>' +
    '<circle cx="' + (cx + 3) + '" cy="' + (cy - 1) + '" r="1.6" fill="#6b4226"/>' +
    '<circle cx="' + cx + '" cy="' + (cy + 3.5) + '" r="1.6" fill="#6b4226"/></g>';
  if (eaten) s += '<path d="M' + (cx - 6) + " " + (cy - 6) + " L" + (cx + 6) + " " + (cy + 6) +
                  " M" + (cx + 6) + " " + (cy - 6) + " L" + (cx - 6) + " " + (cy + 6) +
                  '" stroke="#b34a37" stroke-width="2.5" stroke-linecap="round"/>';
  return s;
}
function subPicSVG(a, b) {
  let s = "";
  for (let i = 0; i < a; i++) s += biscuitG(13 + (i % 6) * 20, 14 + Math.floor(i / 6) * 21, i >= a - b);
  const w = 7 + Math.min(a, 6) * 20, h = 6 + Math.ceil(a / 6) * 21;
  return '<svg viewBox="0 0 ' + w + " " + h + '" style="height:' + Math.min(88, h * 1.8) + 'px">' + s + '</svg>';
}

// real UK money: copper rounds, silver rounds, heptagonal 20p/50p,
// 12-sided bimetallic £1, gold-ringed £2, coloured £5/£10/£20 notes
function polyPts(cx, n, r, rot) {
  const p = [];
  for (let i = 0; i < n; i++) {
    const a = rot + i * 2 * Math.PI / n;
    p.push((cx + r * Math.sin(a)).toFixed(1) + "," + (-r * Math.cos(a)).toFixed(1));
  }
  return p.join(" ");
}
const MONEY_DEFS =
  '<defs>' +
  '<radialGradient id="mgC" cx="0.35" cy="0.3"><stop offset="0" stop-color="#d09058"/><stop offset="0.7" stop-color="#b5713c"/><stop offset="1" stop-color="#96572a"/></radialGradient>' +
  '<radialGradient id="mgS" cx="0.35" cy="0.3"><stop offset="0" stop-color="#eceff2"/><stop offset="0.7" stop-color="#c6c9d2"/><stop offset="1" stop-color="#a2a5b0"/></radialGradient>' +
  '<radialGradient id="mgG" cx="0.35" cy="0.3"><stop offset="0" stop-color="#f0d070"/><stop offset="0.7" stop-color="#d9b13a"/><stop offset="1" stop-color="#b08a24"/></radialGradient>' +
  '</defs>';
// beaded edge ring, like the milled border on real coins
function beadRing(x, r) {
  return '<circle cx="' + x + '" cy="0" r="' + r + '" fill="none" stroke="rgba(58,48,38,0.35)" stroke-width="1.1" stroke-dasharray="0.1 2.4" stroke-linecap="round"/>';
}
// wording curved around the rim, like the real coin
function arcText(x, r, txt, col) {
  const id = "ar" + x + "_" + Math.round(r * 10);
  // shrink the lettering until the words fit their arc
  const fs = Math.min(4.4, (Math.PI * r) / (txt.length * 0.82));
  return '<path id="' + id + '" d="M ' + (x - r) + ' 1 A ' + r + " " + r + ' 0 0 1 ' + (x + r) + ' 1" fill="none"/>' +
    '<text font-size="' + fs.toFixed(1) + '" font-weight="700" letter-spacing="0.4" fill="' + col + '">' +
    '<textPath href="#' + id + '" startOffset="50%" text-anchor="middle">' + txt + '</textPath></text>';
}
// the Royal Shield series (2008–) — what children see in class:
// each coin from 1p to 50p carries a SEGMENT of the Royal Shield of Arms
// a proper lion passant: four legs, raised forepaw, tail curling over the back
const LION_PASSANT =
  'M-5 3 L-5 2.2 L-4.2 2.2 L-4.2 0.6 C -4.2 -0.1 -3.8 -0.6 -3.2 -0.8 L1 -0.8 ' +
  'L1.4 -2.2 C 1.5 -2.9 2.3 -3.3 2.9 -2.9 L3.6 -2.4 L4.6 -2.2 C 5 -2 4.9 -1.5 4.4 -1.4 ' +
  'L3.6 -1.3 L3.5 -0.4 C 3.4 0.2 3 0.6 2.4 0.7 L2.4 1 L3.2 1.2 L3.2 2 L2.4 2 L2.4 3 L1.5 3 ' +
  'L1.5 1.6 L0 1.6 L0 3 L-0.9 3 L-0.9 1.6 L-2.4 1.6 L-2.4 3 Z';
function lionP(x, y, s, col) {
  return '<g transform="translate(' + x + ' ' + y + ') scale(' + s + ')">' +
    '<path d="' + LION_PASSANT + '" fill="' + col + '"/>' +
    '<path d="M-4.2 0.2 C -5.8 -0.5 -6.1 -1.9 -5.1 -2.5 C -5.5 -1.5 -5 -0.7 -3.9 -0.3 Z" fill="' + col + '"/>' +
    '<path d="M2.1 -3.1 L1.8 -3.9 L2.6 -3.4 Z" fill="' + col + '"/>' +
    '</g>';
}
function harpSVG(x, y, s, col) {
  return '<g transform="translate(' + x + ' ' + y + ') scale(' + s + ')">' +
    '<path d="M-2.6 -4.6 C 1.2 -6.2 3.4 -3.2 2.9 0.6 L2 4.4 L-2.9 4.4 C -3.5 1 -3.5 -1.8 -2.6 -4.6 Z" fill="none" stroke="' + col + '" stroke-width="1"/>' +
    '<path d="M-1.6 -3.6 L-0.7 4.4 M0.3 -4.3 L0.9 4.4 M1.8 -4.2 L2.2 4.1" stroke="' + col + '" stroke-width="0.6"/></g>';
}
function coinEmblem(v, col) {
  const seg = w => '<path d="' + w + '" stroke="' + col + '" stroke-width="0.9" fill="none"/>';
  if (v === 1) // 1p: the harp quarter, big and proud like on the real penny
    return seg("M-7 -4.2 L7 -4.2 M3.2 -4.2 L3.2 7.5") + harpSVG(-1.4, 2.2, 1.35, col);
  if (v === 2) // 2p: the rampant lion of Scotland filling its quarter
    return seg("M-6.8 -6.8 L6.8 -6.8 L6.8 6.8 L-6.8 6.8 Z") +
      '<g transform="scale(1.55)"><path d="M-0.8 4.2 L-0.8 1.6 C -2.4 1 -2.7 -0.8 -1.6 -1.9 L-0.5 -3 C -1.2 -4.2 -0.1 -5.4 1 -4.7 L1.8 -3.9 C 2.9 -4.1 3.3 -3.2 2.6 -2.5 L1.5 -1.4 C 2.4 -0.1 1.9 1.4 0.8 2 L0.8 4.2 Z" fill="' + col + '"/>' +
      '<path d="M-0.8 3.2 C -2 2.6 -2.2 1.9 -1.8 1.4" stroke="' + col + '" stroke-width="0.45" fill="none"/></g>';
  if (v === 5) // 5p: the centre of the shield, wording straight across like the real coin
    return '<g opacity="0.75">' + seg("M0 -7 L0 7 M-7 -2.5 L7 -2.5") + lionP(-3.6, -4.8, 0.6, col) + harpSVG(3.8, 2.6, 0.55, col) +
      '<path d="M-4 1.6 C -3.2 2.4 -3.2 3.8 -4 4.6" stroke="' + col + '" stroke-width="0.7" fill="none"/></g>';
  if (v === 10) // 10p: the three lions passant of England
    return lionP(0, -4.6, 0.95, col) + lionP(0, 0.2, 0.95, col) + lionP(0, 5, 0.95, col);
  if (v === 20) // 20p: a diagonal slice across the lions quarter
    return seg("M-7 4 L4 -7 M-5 7 L7 -5") + lionP(-2.6, -1.6, 0.8, col) + lionP(2.8, 2.6, 0.7, col);
  if (v === 50) // 50p: the shield's pointed base
    return seg("M-6.5 -7 C -6 0 -4 4.5 0 7 C 4 4.5 6 0 6.5 -7") + seg("M0 -7 L0 7") +
      lionP(-3.2, -3.4, 0.7, col) + harpSVG(3, -2.4, 0.62, col);
  if (v === 100) // £1: rose, leek, thistle & shamrock under the coronet
    return '<path d="M-4.4 -2.6 L4.4 -2.6 L3.6 -5.6 L1.8 -3.8 L0 -6.2 L-1.8 -3.8 L-3.6 -5.6 Z" fill="' + col + '"/>' +
      '<g fill="' + col + '"><circle cx="-3.4" cy="0.6" r="1.7"/><circle cx="-1.1" cy="1.4" r="1.5"/><circle cx="1.2" cy="1" r="1.6"/><circle cx="3.4" cy="0.8" r="1.4"/></g>' +
      '<path d="M-3.4 2.2 L-3.4 5 M-1.1 2.8 L-1.1 5 M1.2 2.6 L1.2 5 M3.4 2.2 L3.4 5" stroke="' + col + '" stroke-width="0.8"/>';
  // £2: the concentric technology rings with cog teeth
  return '<circle r="7.6" fill="none" stroke="' + col + '" stroke-width="1"/><circle r="4.4" fill="none" stroke="' + col + '" stroke-width="1"/>' +
    '<circle r="1.4" fill="' + col + '"/>' +
    '<path d="M0 -7.6 V-4.4 M0 7.6 V4.4 M-7.6 0 H-4.4 M7.6 0 H4.4 M-5.4 -5.4 L-3.1 -3.1 M5.4 5.4 L3.1 3.1 M-5.4 5.4 L-3.1 3.1 M5.4 -5.4 L3.1 -3.1" stroke="' + col + '" stroke-width="0.8"/>';
}
const COIN_WORD = { 1: "ONE PENNY", 2: "TWO PENCE", 5: "FIVE PENCE", 10: "TEN PENCE", 20: "TWENTY PENCE", 50: "FIFTY PENCE", 100: "ONE POUND", 200: "TWO POUNDS" };
// photos of the real coins (data URIs, filled by the build step); SVG drawing is the fallback
const COIN_IMG = {
  1: "data:image/png;base64,",
  2: "data:image/png;base64,",
  5: "data:image/png;base64,",
  10: "data:image/png;base64,",
  20: "data:image/png;base64,",
  50: "data:image/png;base64,",
  100: "data:image/png;base64,",
  200: "data:image/png;base64,"
};
// true relative sizes (1p 20mm … 50p 27mm)
const COIN_R = { 1: 14, 2: 18, 5: 12.5, 10: 17, 20: 15, 50: 19, 100: 16, 200: 19.5 };
function coinSVG1(v, x) {
  const r = COIN_R[v];
  if (COIN_IMG[v]) {
    // real coin photo (transparent background, true relative size)
    return '<image href="' + COIN_IMG[v] + '" x="' + (x - r) + '" y="' + (-r) + '" width="' + 2 * r + '" height="' + 2 * r + '"/>';
  }
  let body, ink;
  if (v <= 2) {
    ink = "#6e421c";
    body = '<circle cx="' + x + '" cy="0" r="' + r + '" fill="url(#mgC)" stroke="#7a4a20" stroke-width="1.2"/>' + beadRing(x, r - 1.8);
  } else if (v <= 10) {
    ink = "#74747e";
    body = '<circle cx="' + x + '" cy="0" r="' + r + '" fill="url(#mgS)" stroke="#84848e" stroke-width="1.2"/>' + beadRing(x, r - 1.8);
  } else if (v <= 50) {
    ink = "#74747e";
    body = '<polygon points="' + polyPts(x, 7, r, 0) + '" fill="url(#mgS)" stroke="#84848e" stroke-width="1.2"/>' +
           '<polygon points="' + polyPts(x, 7, r - 2.2, 0) + '" fill="none" stroke="rgba(58,48,38,0.25)" stroke-width="0.8"/>';
  } else if (v === 100) {
    ink = "#74747e";
    body = '<polygon points="' + polyPts(x, 12, r, 0.13) + '" fill="url(#mgG)" stroke="#96741c" stroke-width="1.2"/>' +
           '<circle cx="' + x + '" cy="0" r="' + (r - 5) + '" fill="url(#mgS)"/>';
  } else {
    ink = "#74747e";
    body = '<circle cx="' + x + '" cy="0" r="' + r + '" fill="url(#mgG)" stroke="#96741c" stroke-width="1.2"/>' +
           '<circle cx="' + x + '" cy="0" r="' + (r - 6) + '" fill="url(#mgS)"/>';
  }
  const wordInk = v >= 100 ? "#8a6a1c" : ink;
  const wording = v === 5
    ? '<text x="' + x + '" y="0.6" text-anchor="middle" font-size="3.5" font-weight="800" letter-spacing="0.3" fill="' + ink + '">FIVE PENCE</text>'
    : arcText(x, r - 5.2, COIN_WORD[v], wordInk);
  return body +
    '<g transform="translate(' + x + ' 1.5) scale(' + (r / 16).toFixed(2) + ') translate(' + (-x) + ' 0)">' +
    '<g transform="translate(' + x + ' 0)">' + coinEmblem(v, ink) + '</g></g>' +
    wording;
}
function noteSVG1(v, x) {
  const col = v === 500 ? ["#aedce0", "#3f93a3", "Five"] : v === 1000 ? ["#ecd0ac", "#b8804a", "Ten"]
            : v === 2000 ? ["#ddc7ec", "#8f62b3", "Twenty"] : ["#f2c6be", "#bc4a52", "Fifty"];
  const lbl = "£" + v / 100;
  return '<rect x="' + (x - 31) + '" y="-19" width="62" height="38" rx="4" fill="' + col[0] + '" stroke="' + col[1] + '" stroke-width="1.5"/>' +
    // wavy guilloché-style background lines
    '<path d="M' + (x - 31) + ' -6 C ' + (x - 15) + ' -10 ' + (x + 15) + ' -2 ' + (x + 31) + ' -6 M' + (x - 31) + ' 8 C ' + (x - 15) + ' 4 ' + (x + 15) + ' 12 ' + (x + 31) + ' 8" stroke="' + col[1] + '" stroke-width="0.6" fill="none" opacity="0.45"/>' +
    // portrait
    '<ellipse cx="' + (x + 15) + '" cy="1" rx="8.5" ry="12" fill="none" stroke="' + col[1] + '" stroke-width="1.1"/>' +
    '<circle cx="' + (x + 15) + '" cy="-3" r="3.2" fill="' + col[1] + '" opacity="0.7"/>' +
    '<path d="M' + (x + 10) + ' 8 C ' + (x + 12) + ' 2 ' + (x + 18) + ' 2 ' + (x + 20) + ' 8 Z" fill="' + col[1] + '" opacity="0.7"/>' +
    // see-through security window + foil patch
    '<rect x="' + (x - 29) + '" y="2" width="7" height="14" rx="3.5" fill="#fdf8ec" stroke="' + col[1] + '" stroke-width="0.8" opacity="0.9"/>' +
    '<rect x="' + (x + 1) + '" y="-16" width="5" height="9" rx="1" fill="#fff" opacity="0.55"/>' +
    '<text x="' + x + '" y="-11.5" text-anchor="middle" font-size="4.6" font-weight="700" letter-spacing="0.5" fill="' + col[1] + '">BANK OF ENGLAND</text>' +
    '<text x="' + (x - 12) + '" y="5.5" text-anchor="middle" font-size="13" font-weight="800" font-family="Georgia, serif" fill="#3a3026">' + lbl + '</text>' +
    '<text x="' + (x - 12) + '" y="12.5" text-anchor="middle" font-size="4.6" font-style="italic" fill="' + col[1] + '">' + col[2] + ' Pounds</text>' +
    '<text x="' + (x + 24) + '" y="16" text-anchor="middle" font-size="6.5" font-weight="700" fill="' + col[1] + '">' + lbl + '</text>';
}
function moneySVG(vals) {
  let x = 4;
  const parts = [];
  for (const v of vals) {
    if (v >= 500) { parts.push(noteSVG1(v, x + 32)); x += 68; }
    else { parts.push(coinSVG1(v, x + 21)); x += 44; }
  }
  // bigger when there are few items, so the coin designs are studyable
  const hpx = vals.length <= 2 ? 86 : vals.length <= 4 ? 72 : 60;
  return '<svg viewBox="0 -24 ' + (x + 4) + ' 48" style="height:' + hpx + 'px">' + MONEY_DEFS + parts.join("") + "</svg>";
}
// how a grown-up would describe each coin to a child
const COIN_DESC = {
  1: "small copper penny", 2: "big copper two pence", 5: "tiny silver five pence",
  10: "big silver ten pence", 20: "small seven-sided twenty pence", 50: "big seven-sided fifty pence",
  100: "golden one pound coin", 200: "two-coloured two pound coin"
};
const MONEY_NAME = {
  1: "one penny", 2: "two pence", 5: "five pence", 10: "ten pence", 20: "twenty pence", 50: "fifty pence",
  100: "one pound", 200: "two pounds", 500: "five pounds", 1000: "ten pounds", 2000: "twenty pounds", 5000: "fifty pounds"
};
function clockSVG(hr, mm) {
  const ha = (hr % 12) * 30 + mm * 0.5, ma = mm * 6;
  let marks = "";
  for (let i = 1; i <= 12; i++) {
    const a = i * 30 * Math.PI / 180;
    marks += '<text x="' + (50 + 37 * Math.sin(a)).toFixed(1) + '" y="' + (53 - 37 * Math.cos(a)).toFixed(1) +
      '" text-anchor="middle" font-size="9" font-weight="700" fill="#5a4a2f">' + i + "</text>";
  }
  return '<svg viewBox="0 0 100 100" style="height:112px">' +
    '<circle cx="50" cy="50" r="47" fill="#fff" stroke="#5a4a2f" stroke-width="3"/>' + marks +
    '<line x1="50" y1="50" x2="50" y2="31" stroke="#3a3026" stroke-width="4.5" stroke-linecap="round" transform="rotate(' + ha + ' 50 50)"/>' +
    '<line x1="50" y1="50" x2="50" y2="19" stroke="#b34a37" stroke-width="3" stroke-linecap="round" transform="rotate(' + ma + ' 50 50)"/>' +
    '<circle cx="50" cy="50" r="3" fill="#3a3026"/></svg>';
}

